SELECT 
FROM meta.report_template
WHERE tenant_id = #{tenantId}

    AND category = #{category}


    AND status = #{status}


    AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM meta.report_template
WHERE tenant_id = #{tenantId}

    AND category = #{category}


    AND status = #{status}


    AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')

SELECT FROM meta.report_template WHERE status = COALESCE(#{status}, 'ACTIVE') AND (tenant_id = 0 OR (tenant_id = #{tenantId} AND is_public = true))
AND category = #{category}
AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM meta.report_template WHERE status = COALESCE(#{status}, 'ACTIVE') AND (tenant_id = 0 OR (tenant_id = #{tenantId} AND is_public = true))
AND category = #{category}
AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')
